{{ 'section-blog-post.css' | asset_url | stylesheet_tag }}
{{ 'component-grid.css' | asset_url | stylesheet_tag }}
<link rel="stylesheet" href="{{ 'component-fancybox.css' | asset_url }}" media="print" onload="this.media='all'">
<noscript>{{ 'component-fancybox.css' | asset_url | stylesheet_tag }}</noscript>
<script src="{{ 'fancybox.js' | asset_url }}" defer="defer"></script>

{{ 'article-gallery-lookbook-style.css' | asset_url | stylesheet_tag }}
{{ 'lookbook-script.js' | asset_url | script_tag }}

{%- liquid
    assign padding_top = section.settings.mg_top_desktop | append: 'px'
    assign padding_bottom = section.settings.mg_bottom_desktop | append: 'px'
    assign padding_top_tablet = section.settings.mg_top_tablet | append: 'px'
    assign padding_bottom_tablet = section.settings.mg_bottom_tablet | append: 'px'
    assign padding_top_mobile = section.settings.mg_top_mobile | append: 'px'
    assign padding_bottom_mobile = section.settings.mg_bottom_mobile | append: 'px'
    assign container = section.settings.container
    assign media_size = section.settings.image_ratio
    assign show_breadcrumb = section.settings.show_breadcrumb
    assign breadcrumb_alignment = section.settings.breadcrumb_alignment
    assign breadcrumb_bg = section.settings.breadcrumb_bg
    assign breadcrumb_gradient = section.settings.breadcrumb_gradient
    assign breadcrumb_bg_mb = section.settings.breadcrumb_bg_mb
    assign breadcrumb_gradient_mb = section.settings.breadcrumb_gradient_mb
    assign show_page_title = section.settings.show_page_title
    assign page_title_alignment = section.settings.page_title_alignment
    assign show_author = section.settings.show_author
    assign show_date = section.settings.show_date
    assign show_next_prev = section.settings.show_next_prev
    assign show_share = section.settings.show_share
    assign show_tags = section.settings.show_tags
    assign show_main_img = section.settings.show_main_img
    assign title_font = section.settings.title_font
    assign title_font_size = section.settings.title_font_size | append: 'px'
    assign title_mobile_font_size = section.settings.title_mobile_font_size | append: 'px'
    assign title_font_weight = section.settings.title_font_weight
    assign title_text_transform = section.settings.title_text_transform

    assign show_sidebar = section.settings.show_sidebar
    if show_sidebar
        assign show_collapse = section.settings.show_collapse
        assign sidebar_position = section.settings.sidebar_position
        assign sidebar_collapse_default = section.settings.sidebar_collapse_default
        assign enable_sticky = section.settings.enable_sticky
    endif
    if show_sidebar and section.blocks.size > 0
        assign sidebar_heading_font = section.settings.sidebar_heading_font
        assign sidebar_heading_font_size = section.settings.sidebar_heading_font_size
        assign sidebar_heading_font_weight = section.settings.sidebar_heading_font_weight
        assign sidebar_heading_text_transform = section.settings.sidebar_heading_text_transform
        assign sidebar_heading_margin_top = sidebar_heading_font_size | times: settings.line_height | minus: sidebar_heading_font_size | divided_by: 2
    endif
    assign background_color = section.settings.background_color
    assign title_color = section.settings.title_color
    assign info_color = section.settings.info_color
    assign text_color = section.settings.text_color
    assign text_font_size = section.settings.text_font_size | append: 'px'
    assign text_font_weight = section.settings.text_font_weight
    assign text_text_transform = section.settings.text_text_transform
    assign info_font_size = section.settings.info_font_size | append: 'px'
    assign info_font_weight = section.settings.info_font_weight
    assign info_text_transform = section.settings.info_text_transform
    assign info_font_style = section.settings.info_font_style
-%}

<style type="text/css" media="screen">
    :root {
        {% if title_font == 'font_1' %}
            --title-font-{{ section.id }}: var(--font-1-family);
        {% elsif title_font == 'font_2' %}
            --title-font-{{ section.id }}: var(--font-2-family);
        {% elsif title_font == 'font_3' %}
            --title-font-{{ section.id }}: var(--font-3-family);
        {% endif %}
    }

    #ArticleSection-{{ section.id }}{
        padding-top: {{ padding_top }};
        padding-bottom: {{ padding_bottom }};
    }

    #ArticleSection-{{ section.id }} .article-heading .title{
        color: {{ title_color }};
        font-family: var(--title-font-{{ section.id }});
        font-size: {{ title_mobile_font_size }};
        font-weight: {{ title_font_weight }};
        text-transform: {{ title_text_transform }};
    }

    {% if show_sidebar and section.blocks.size > 0 %}
        #ArticleSection-{{ section.id }} .sidebarBlock-heading{
            font-family: var(--sidebar-heading-font);
            font-size: {{ sidebar_heading_font_size | append: 'px' }};
            font-weight: {{ sidebar_heading_font_weight }};
            text-transform: {{ sidebar_heading_text_transform }};
        }

        #ArticleSection-{{ section.id }} .sidebarBlock:first-child .sidebarBlock-heading{
            margin-top: {{ sidebar_heading_margin_top | append: 'px' | prepend: '-' }};
        }
    {% endif %}

    #ArticleSection-{{ section.id }} .blog-block-item .item {
        background-color: {{ background_color }};
    }

    #ArticleSection-{{ section.id }} .halo-article-content .info,
    #ArticleSection-{{ section.id }} .halo-article-content .comment {
        color: {{ info_color }};
        font-size: {{ info_font_size }};
        font-weight: {{ info_font_weight }};
        text-transform: {{ info_text_transform }};
        font-style: {{ info_font_style }};
    }

    #ArticleSection-{{ section.id }} .halo-article-content .article-content,
    #ArticleSection-{{ section.id }} .halo-article-content .article-content li {
        color: {{ text_color }};
        font-size: {{ text_font_size }};
        font-weight: {{ text_font_weight }};
        text-transform: {{ text_text_transform }};
    }

    @media (max-width: 1024px) {
        #ArticleSection-{{ section.id }}{
            padding-top: {{ padding_top_tablet }};
            padding-bottom: {{ padding_bottom_tablet }};
        }

        #ArticleSection-{{ section.id }} .breadcrumb {
            background: {% if breadcrumb_gradient_mb != blank and breadcrumb_gradient_mb != 'rgba(0,0,0,0)' %}{{ breadcrumb_gradient_mb }}{% elsif breadcrumb_bg_mb != blank and breadcrumb_bg_mb != 'rgba(0,0,0,0)' %}{{ breadcrumb_bg_mb }}{% endif %};
        }
    }

    @media (max-width: 550px) {
        #ArticleSection-{{ section.id }}{
            padding-top: {{ padding_top_mobile }};
            padding-bottom: {{ padding_bottom_mobile }};
        }
    }

    @media (min-width: 768px){
        #ArticleSection-{{ section.id }} .article-heading .title{
            font-size: {{ title_font_size }};
        }
    }

    @media (min-width: 1025px) {
        #ArticleSection-{{ section.id }} .breadcrumb-container {
            position: relative;
        }

        #ArticleSection-{{ section.id }} .breadcrumb::after {
            content: "";
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: {% if breadcrumb_gradient != blank and breadcrumb_gradient != 'rgba(0,0,0,0)' %}{{ breadcrumb_gradient }}{% elsif breadcrumb_bg != blank and breadcrumb_bg != 'rgba(0,0,0,0)' %}{{ breadcrumb_bg }}{% endif %};
            z-index: -1;
        }
    }
</style>

<article data-section-id="{{ section.id }}" data-section-type="article-template" id="ArticleSection-{{ section.id }}" data-section="{{ section.id }}" class="article-template" itemscope itemtype="http://schema.org/BlogPosting">
    <div class="container container-{{ container }} {{ blog.title | escape }}">
        {%- if show_breadcrumb -%}
            {% render 'breadcrumb',
                alignment: breadcrumb_alignment,
                blog: blog
            %}
        {%- endif -%}
        {%- if show_sidebar -%}
            <div class="header-with-sidebar{% if settings.banner_animation == 'effect_fade_up' %} scroll-trigger animate--slide-in{% endif %}">
        {% endif %}
            {%- if show_page_title -%}
                <h2 class="page-header text-{{ page_title_alignment }}">
                    {{ blog.title | escape }}
                </h2>
            {%- endif -%}
            {%- if show_sidebar and section.blocks.size > 0 -%}
                <div class="sidebar-toogle" data-sidebar>
                    {% render 'icon-sidebar' %}
                </div>
            {%- endif -%}
        {% if show_sidebar %}
            </div>
        {% endif %}
        <div class="halo-article-block">
            {%- if show_sidebar and section.blocks.size > 0 -%}
                {{ 'component-main-sidebar.css' | asset_url | stylesheet_tag }}
                <div class="page-sidebar page-sidebar-{{ sidebar_position }} page-sidebar--vertical sidebar--{{ section.settings.sidebar_layout }}{% if enable_sticky %} has-sticky{% endif %}" id="halo-sidebar">
                    <a href="javascript:void(0)" class="halo-sidebar-close" data-close-sidebar role="button">
                        <span class="visually-hidden">{{ 'general.common.close' | t }}</span>
                        {% render 'icon-close' %}
                    </a>
                    <div class="halo-sidebar-header text-left">
                        <span class="title">
                            {{ 'sections.sidebar.title' | t }}
                        </span>
                    </div>
                    <div class="halo-sidebar-wrapper custom-scrollbar{% if settings.banner_animation == 'effect_fade_up' %} scroll-trigger animate--slide-in{% endif %}">
                        {% render 'sidebar',
                            section: section,
                            show_collapse: show_collapse,
                            sidebar_collapse: sidebar_collapse_default
                        %}
                    </div>
                </div>
            {%- endif -%}
            <div class="page-content">
              <div class="halo-article-content{% if settings.banner_animation == 'effect_fade_up' %} scroll-trigger animate--slide-in{% endif %}">
                  <div class="article-header">
                      <div class="article-heading text-left">
                          <h1 class="title">
                              {{ article.title }}
                          </h1>
                          {%- if show_author or show_date or blog.comments_enabled? -%}
                              <div class="info">
                                  {%- if show_author -%}
                                      <span class="info-item author">
                                          <span>{{ 'blogs.article.by' | t }}</span>
                                          <span class="text">{{ article.author }}</span>
                                      </span>
                                  {%- endif -%}
                                  {%- if show_date -%}
                                      <span class="info-item date">
                                          {{ article.published_at | date: "%d %b %Y" }}
                                      </span>
                                  {%- endif -%}
                                  {%- if blog.comments_enabled? -%}
                                      <a class="info-item comment" href="{{ article.url }}#comments">
                                          {{ 'blogs.article.comments' | t: count: article.comments_count }}
                                      </a>      
                                  {%- endif -%}
                              </div>
                          {%- endif -%}
                      </div>
                      {%- if article.image and show_main_img -%}
                          <div class="article-image">
                              <a href="{{ article.url }}" class="image">
                                 <img srcset="{% if article.image.width >= 350 %}{{ article.image | img_url: '350x' }} 350w,{% endif %}
                                  {% if article.image.width >= 700 %}{{ article.image | img_url: '700x' }} 700w,{% endif %}
                                  {% if article.image.width >= 749 %}{{ article.image | img_url: '749x' }} 749w,{% endif %}
                                  {% if article.image.width >= 1498 %}{{ article.image | img_url: '1498x' }} 1498w,{% endif %}
                                  {% if article.image.width >= 1100 %}{{ article.image | img_url: '1100x' }} 1100w,{% endif %}
                                  {% if article.image.width >= 2200 %}{{ article.image | img_url: '2200x' }} 2200w,{% endif %}"
                                  sizes="(min-width: 1200px) 1100px, (min-width: 750px) calc(100vw - 10rem), 100vw"
                                  src="{{ article.image | img_url: '1100x' }}"
                                  {% unless settings.enable_layout_rtl %} loading="lazy"{% endunless %}
                                  width="{{ article.image.width }}"
                                  height="{{ article.image.height }}"
                                  alt="{{ article.image.alt | escape }}">
                              </a>
                          </div>
                      {%- endif -%}
                  </div>
                  <div class="article-body">
                      <div class="article-content halo-text-format{% if settings.banner_animation == 'effect_fade_up' %} scroll-trigger animate--slide-in{% endif %}">
                          {{ article.content }}
                      </div>
                      {%- for block in section.blocks -%}
                        {%- if block.type == 'image_gallery' -%}
                            {%- liquid
                                assign swipe = block.settings.image_gallery_swipe_on_mobile
                                assign column = block.settings.column
                                assign column_mb = block.settings.column_mb
                                assign type_image_gallery = block.settings.type_image_gallery
                                assign image_gallery_title = block.settings.image_gallery_title
                                assign color_title = block.settings.color_title
                                assign fontsize_title = block.settings.fontsize_title
                                assign fontsize_title_mb = block.settings.fontsize_title_mb
                                assign margin_bottom_title = block.settings.margin_bottom_title
                                assign item_distance = block.settings.item_distance

                                assign lookbook_style = block.settings.lookbook_style
                                assign dot_desktop_size = block.settings.dot_desktop_size | append: 'px'
                                assign dot_mobile_size = block.settings.dot_mobile_size | append: 'px'
                                assign dot_shadow_color = block.settings.dot_shadow_color | color_modify: 'alpha', 0.5
                                assign dot_outer_color = block.settings.dot_outer_color
                                assign show_dot_number = block.settings.show_dot_number
                                assign show_dot_number_mobile = block.settings.show_dot_number_mobile
                                assign dot_inner_color = block.settings.dot_inner_color
                                assign number_desktop_size = block.settings.number_desktop_size | append: 'px'
                                assign number_mobile_size = block.settings.number_mobile_size | append: 'px'
                                assign enable_lookbook_width = block.settings.enable_lookbook_width
                                assign lookbook_width = block.settings.lookbook_width | append: 'px'
                                assign lookbook_truncate = block.settings.lookbook_truncate
                                assign show_plus_icon = block.settings.show_plus_icon
                                assign item_distance = block.settings.item_distance
                            -%}

                            <div class="articleGallery-block articleGallery-{{section.id}}{% if settings.banner_animation == 'effect_fade_up' %} scroll-trigger animate--slide-in{% endif %}" id="articleGallery-{{section.id}}">
                                {% if image_gallery_title != blank %}
                                    <div class="halo-block-header text-left" style="
                                            --margin-bottom-title: {{ margin_bottom_title | append: 'px' }}">   
                                        <h3 class="title"
                                            style="--color-title: {{ color_title }};
                                            --fontsize-title: {{ fontsize_title | append: 'px' }};
                                            --fontsize_title_mb: {{ fontsize_title_mb | append: 'px' }};"
                                        >
                                            <span class="text">
                                                {{ image_gallery_title }}
                                            </span>
                                        </h3>
                                    </div>
                                {% endif %}
                                <div class="halo-row column-{{ column }}
                                    {% if swipe == 'slider' %} articleGallery-slider{% endif %}
                                    {% if item_distance == 0 %} not-distance{% endif %}
                                    {% if swipe == 'scroll' %} scroll-snap-mobile disable-srollbar{% endif %}
                                    {% if column_mb == '2' %} column-mb-2{% endif %}" 
                                    data-col="{{ column }}" 
                                    data-show-lookbook-container
                                    style="--row-distance-style: {{ item_distance | prepend: '-' | append: 'px' }}; 
                                    --item-distance-style: {{ item_distance | append: 'px' }};"
                                >
                                    {% for i in (1..8) %}
                                        {% capture image %}image_{{ i }}{% endcapture %}
                                        {% capture show_image %}show_image_{{ i }}{% endcapture %}
                                        {% capture link %}link_{{ i }}{% endcapture %}

                                        {% capture product_1 %}lb_product_{{ i }}_1{% endcapture %}
                                        {% capture left_1 %}horizontal_pos_{{ i }}_1{% endcapture %}
                                        {% capture top_1 %}vertical_pos_{{ i }}_1{% endcapture %}
                                        {% capture lookbook_pos_1 %}lookbook_pos_{{ i }}_1{% endcapture %}

                                        {% capture product_2 %}lb_product_{{ i }}_2{% endcapture %}
                                        {% capture left_2 %}horizontal_pos_{{ i }}_2{% endcapture %}
                                        {% capture top_2 %}vertical_pos_{{ i }}_2{% endcapture %}
                                        {% capture lookbook_pos_2 %}lookbook_pos_{{ i }}_2{% endcapture %}

                                        {%- if block.settings[show_image] -%}
                                            <div class="halo-item">
                                                <div class="imgGallery-item lookbook-image-item {% if enable_lookbook_width %}width-restricted{% endif %}" data-lookbook-item-container
                                                    style="
                                                        --dot-desktop-size: {{ dot_desktop_size }};
                                                        --dot-mobile-size: {{ dot_mobile_size }};
                                                        --dot-shadow-color: {{ dot_shadow_color }};
                                                        --dot-outer-color: {{ dot_outer_color }};
                                                        --dot-inner-color: {{ dot_inner_color }};
                                                        --dot-number-desktop-size: {{ number_desktop_size }};
                                                        --dot-number-mobile-size: {{ number_mobile_size }};
                                                        --max-width: {{ lookbook_width }};
                                                        --des-max-width: {% if des_width > 0 %}{{ des_width | append: 'px' }}{% else %}unset{% endif %};
                                                        --truncate-line: {{ lookbook_truncate }};
                                                    "
                                                >   
                                                <div class="img-box">
                                                    {% if block.settings[image] != blank %}
                                                        {%- assign preview_img = block.settings[image] -%}
                                                        <a 
                                                            {% if type_image_gallery == 'link' %}
                                                                {% if block.settings[link] == blank %} role="link" aria-disabled="true"{% else %} href="{{ block.settings[link] }}"{% endif %} class="image-zoom adaptive_height"
                                                            {% else %}
                                                                href="{{ preview_img | img_url: 'master' }}" data-fancybox="images" class="image-zoom adaptive_height fancybox"
                                                            {% endif %}
                                                            style="padding-top: {{ 1 | divided_by: preview_img.aspect_ratio | times: 100 }}%">
                                                                <img {% render 'lazyload',preview_img: preview_img %} />
                                                                {% if settings.enable_lazyload %}<span class="data-lazy-loading"></span>{% endif %}
                                                        </a>
                                                    {% else %}
                                                        <a {% if block.settings[link] == blank %} role="link" aria-disabled="true"{% else %} href="{{ block.settings[link] }}"{% endif %} class="image-zoom">
                                                            <div class="not_img" style="--height_not_img: 370px">290 x 370px</div>
                                                        </a>
                                                    {% endif %}
                                                </div>
                                                {% if block.settings[product_1] != blank %}
                                                    {% assign top = block.settings[top_1] | append: '%' %}
                                                    {% assign left = block.settings[left_1] | append: '%' %}

                                                    {% render 'lookbook-modal-wrapper',
                                                        lookbook_style: lookbook_style,
                                                        top: top,
                                                        left: left,
                                                        show_dot_number: show_dot_number,
                                                        show_dot_number_mobile: show_dot_number_mobile,
                                                        lookbook_pos: block.settings[lookbook_pos_1],
                                                        product: block.settings[product_1],
                                                        show_plus_icon: show_plus_icon,
                                                        num: 1,
                                                    %}  
                                                {% endif %}
                                                {% if block.settings[product_2] != blank %}
                                                    {% assign top = block.settings[top_2] | append: '%' %}
                                                    {% assign left = block.settings[left_2] | append: '%' %}

                                                    {% render 'lookbook-modal-wrapper',
                                                        lookbook_style: lookbook_style,
                                                        top: top,
                                                        left: left,
                                                        show_dot_number: show_dot_number,
                                                        show_dot_number_mobile: show_dot_number_mobile,
                                                        lookbook_pos: block.settings[lookbook_pos_2],
                                                        product: block.settings[product_2],
                                                        show_plus_icon: show_plus_icon,
                                                        num: 2,
                                                    %}  
                                                {% endif %}
                                            </div>
                                        </div>
                                    {%- endif -%}
                                    {% endfor %}
                                </div>
                            </div>
                          {%- elsif block.type == 'lookbook' -%}
                              {%- liquid
                                  assign image = block.settings.image
                                  assign preview_img = block.settings.image
                                  assign link = block.settings.link
                                  assign margin_bottom = block.settings.margin_bottom
                              -%}
                              <div class="articleLookbook-block"
                                  style="--lookbook-margin-bottom: {{ margin_bottom | append: 'px' }}";
                              >
                                  <div class="articleLookbook-item">
                                      {%- if image != blank -%}
                                          <a class="image image-zoom1 image-adapt adaptive_height"{% if link == blank %} role="link" aria-disabled="true"{% else %} href="{{ link }}"{% endif %} style="padding-top: {{ 1 | divided_by: image.aspect_ratio | times: 100 | append: '%' }}">
                                              <img {% render 'lazyload',preview_img: preview_img %} />
                                              {% if settings.enable_lazyload %}<span class="data-lazy-loading"></span>{% endif %}
                                          </a>
                                      {%- else -%}
                                          <a class="image"{% if link == blank %} role="link" aria-disabled="true"{% else %} href="{{ link }}"{% endif %}>
                                              <div class="not_img" style="--height_not_img: 520px">
                                                930 x 520px
                                              </div>  
                                          </a>
                                      {%- endif -%}
                                  </div>
                              </div>
                          {%- elsif block.type == 'block_quote' -%}
                              {%- liquid
                                  assign enable_bg_color = block.settings.enable_bg_color
                                  assign bg_color_content = block.settings.bg_color_content
                                  assign title = block.settings.title
                                  assign color_title = block.settings.color_title
                                  assign fontsize_title = block.settings.fontsize_title
                                  assign margin_bottom_title = block.settings.margin_bottom_title
                                  assign content = block.settings.content
                                  assign color_content = block.settings.color_content
                                  assign fontsize_content = block.settings.fontsize_content
                                  assign margin_bottom = block.settings.margin_bottom
                              -%}
                              <div class="articleBlockQuote{% if settings.banner_animation == 'effect_fade_up' %} scroll-trigger animate--slide-in{% endif %}"
                                  style="--quote-margin-bottom: {{ margin_bottom | append: 'px' }}";
                              >
                                  <div class="articleBlockQuote-header"
                                      style="--quote-color-title: {{ color_content }};
                                      --quote-fontsize-title: {{ fontsize_title | append: 'px' }};
                                      --quote-margin-bottom-title: {{ margin_bottom_title | append: 'px' }}" 
                                  >
                                      <h3 class="title">{{ title }}</h3>
                                  </div>
                                  <div class="articleBlockQuote-content{% if enable_bg_color %} has-bg{% endif %}"
                                      style="--quote-color-content: {{ color_content }};
                                      --quote-bg-color-content: {{ bg_color_content }};
                                      --quote-fontsize-content: {{ fontsize_content | append: 'px' }}" 
                                  >
                                      {{ content }}
                                  </div>
                              </div>
                          {%- elsif block.type == 'product_block' -%}
                              {% assign position = block.settings.position %}
                              {% if position == 'content' %}
                                  {% render 'halo-side-product-block',
                                      block: block,
                                      show_collapse: false,
                                      sidebar_collapse: sidebar_collapse_default,
                                      position: position
                                  %}
                              {% endif %}
                          {%- endif -%}
                      {%- endfor -%}
                      {%- if show_tags -%}
                          {%- if article.tags.size > 0 -%}
                              <div class="article-tag{% if settings.banner_animation == 'effect_fade_up' %} scroll-trigger animate--slide-in{% endif %}">
                                  <div class="article-tag-row">
                                      <div class="tag-header">
                                          {% render 'icon-tag-solid' %}
                                          <span>{{ 'blogs.article.tags' | t }}</span>
                                      </div>
                                      <ul class="tag-list list-unstyled clearfix">
                                          {%- for tag in article.tags -%}
                                              <li class="item">
                                                <a href="{{ blog.url }}/tagged/{{ tag | handle }}">
                                                  <span class="text">{{ tag }}</span>
                                                </a>
                                              </li>
                                          {%- endfor -%}
                                      </ul>
                                  </div>
                              </div>
                          {%- endif -%}
                      {%- endif -%}
                      {%- if show_share -%}
                          <div class="article-social text-left{% if settings.banner_animation == 'effect_fade_up' %} scroll-trigger animate--slide-in{% endif %}">
                              {% render 'halo-share', product: article %}
                          </div>
                      {%- endif -%}
                  </div>
              </div>
              {%- if show_next_prev -%}
                  {%- if blog.next_article or blog.previous_article -%}
                      <div class="article__pagination{% if settings.banner_animation == 'effect_fade_up' %} scroll-trigger animate--slide-in{% endif %}">
                          <div class="article__pagination--item article__pagination--prev">
                              <a class="button button--secondary button--prev" href="{{ blog.previous_article }}" {% unless blog.previous_article %}disabled{% endunless %}>
                                  <span class="text"> {{ 'blogs.article.prev_post' | t }}</span>
                              </a>
                          </div>
                          <div class="article__pagination--item article__pagination--next">
                              <a class="button button--secondary button--next" href="{{ blog.next_article }}" {% unless blog.next_article %}disabled{% endunless %}>
                                  <span class="text">{{ 'blogs.article.next_post' | t }} </span>
                              </a>
                          </div>
                      </div> 
                  {%- endif -%}
              {%- endif -%}
              {%- if blog.comments_enabled? -%}
                  <div class="article-template__comment-wrapper background-secondary{% if settings.banner_animation == 'effect_fade_up' %} scroll-trigger animate--slide-in{% endif %}">
                      <div id="comments" class="page-width page-width--narrow">
                          {%- if article.comments_count > 0 -%}
                              {%- assign anchorId = '#Comments-' | append: article.id -%}
                              <div class="halo-block-header">
                                  <h3 id="Comments-{{ article.id }}" class="title text-left">
                                      <span class="text">
                                          {{ 'blogs.article.comments' | t: count: article.comments_count }}
                                      </span>
                                  </h3>
                              </div>
                              {%- paginate article.comments by 5 -%}
                                  <div class="article-template__comments">
                                      {%- if comment.status == 'pending' and comment.content -%}
                                          <article id="{{ comment.id }}" class="article-template__comments-comment">
                                              <h4 class="comment-author">
                                                  {{ comment.author }}
                                              </h4>
                                              <div class="comment-body {{ comment.status }}">
                                                  {{ comment.content }}
                                              </div>
                                          </article>
                                      {%- endif -%}

                                      {%- for comment in article.comments -%}
                                          <article id="{{ comment.id }}" class="article-template__comments-comment">
                                              <div class="comment-user">
                                                {% render 'icon-account-2' %}
                                              </div>
                                              <div class="comment-content">
                                                <div class="comment-created-at">
                                                    <span class="comment-date">{{ comment.created_at | date: "%d %b %Y"   }}</span>
                                                    <span class="comment-author">{{ comment.author }}</span>
                                                </div>
                                                <div class="comment-body {{ comment.status }}">
                                                    {{ comment.content }}
                                                </div>
                                              </div>
                                          </article>
                                      {%- endfor -%}
                                      {% render 'pagination',
                                          paginate: paginate,
                                          class: 'order-pagination pagination-wrapper text-center',
                                          anchor: anchorId
                                      %}
                                  </div>
                              {%- endpaginate -%}
                          {%- endif -%}
                          {%- form 'new_comment', article -%}
                              {%- liquid
                                  assign post_message = 'blogs.article.success'
                                  if blog.moderated? and comment.status == 'unapproved'
                                      assign post_message = 'blogs.article.success_moderated'
                                  endif
                              -%}
                              <div class="halo-block-header">
                                  <h3 class="title text-left">
                                      <span class="text">
                                        {{ 'blogs.article.comment_form_title' | t }}
                                      </span>
                                  </h3>
                              </div>
                              {%- if form.errors -%}
                                  {%- if form.errors -%}
                                      <div class="form-message" role="alert">
                                          <div class="alertBox alertBox--error">
                                              <div class="alertBox-message">
                                                  <ul>
                                                      {%- for field in form.errors -%}
                                                          <li>
                                                              <a href="#CommentForm-{{ field }}" class="link">
                                                                  {%- if form.errors.translated_fields[field] contains 'author' -%}
                                                                      {{ 'blogs.article.name' | t }}
                                                                  {%- elsif form.errors.translated_fields[field] contains 'body'-%}
                                                                      {{ 'blogs.article.message' | t }}
                                                                  {%- else -%}
                                                                      {{ form.errors.translated_fields[field] }}
                                                                  {%- endif -%}
                                                                  {{ form.errors.messages[field] }}
                                                              </a>
                                                          </li>
                                                      {%- endfor -%}
                                                  </ul>
                                              </div>
                                          </div>
                                      </div>
                                  {%- endif -%}
                              {%- elsif form.posted_successfully? -%}
                                  <div class="form-message" role="status">
                                      <div class="alertBox alertBox--success">
                                          <p class="alertBox-message">
                                              {{ post_message | t }}
                                          </p>
                                      </div>
                                  </div>
                              {%- endif -%}
                              <div{% if blog.moderated? == false %} class="article-template__comments-fields"{% endif %}>
                                  <div class="article-template__comment-fields form-field-group clearfix">
                                      <div class="form-field{% if form.errors contains "author" %} form-field--error{% endif %}">
                                          <label class="form-label" for="CommentForm-author">
                                              {{ 'blogs.article.name' | t }}
                                          </label>
                                          <input
                                              type="text"
                                              name="comment[author]"
                                              id="CommentForm-author"
                                              class="form-input form-input-hiddenPlaceholder{% if form.errors contains "author" %} form-field--error{% endif %}"
                                              autocomplete="name"
                                              value="{{ form.author }}"
                                              aria-required="true"
                                              {% if form.errors contains 'author' %}
                                                  aria-invalid="true"
                                                  aria-describedby="CommentForm-author-error"
                                              {% endif %}
                                              placeholder="{{ 'blogs.article.name' | t }}"
                                          >
                                      </div>
                                      <div class="form-field{% if form.errors contains "email" %} form-field--error{% endif %}">
                                          <label class="form-label" for="CommentForm-email">
                                              {{ 'blogs.article.email' | t }}
                                          </label>
                                          <input
                                              type="email"
                                              name="comment[email]"
                                              id="CommentForm-email"
                                              autocomplete="email"
                                              class="form-input form-input-hiddenPlaceholder{% if form.errors contains "email" %} form-field--error{% endif %}"
                                              value="{{ form.email }}"
                                              autocorrect="off"
                                              autocapitalize="off"
                                              aria-required="true"
                                              {% if form.errors contains 'email' %}
                                                  aria-invalid="true"
                                                  aria-describedby="CommentForm-email-error"
                                              {% endif %}
                                              placeholder="{{ 'blogs.article.email' | t }}"
                                          >
                                      </div>
                                  </div>
                                  <div class="form-field{% if form.errors contains "body" %} form-field--error{% endif %}">
                                      <label class="form-label" for="CommentForm-body">{{ 'blogs.article.message' | t }}</label>
                                      <textarea
                                          rows="3"
                                          name="comment[body]"
                                          id="CommentForm-body"
                                          class="form-input form-input-hiddenPlaceholder{% if form.errors contains "email" %} form-field--error{% endif %}"
                                          aria-required="true"
                                          {% if form.errors contains 'body' %}
                                              aria-invalid="true"
                                              aria-describedby="CommentForm-body-error"
                                          {% endif %}
                                          placeholder="{{ 'blogs.article.message' | t }}"
                                      >
                                          {{ form.body }}
                                      </textarea>
                                  </div>
                              </div>
                              <div class="form-actions text-left">
                                  {%- if blog.moderated? -%}
                                      <p class="form-note article-template__comment-warning">{{ 'blogs.article.moderated' | t }}</p>
                                  {%- else -%}
                                      <p class="form-note article-template__comment-warning">{{ 'blogs.article.moderated-all' | t }}</p>
                                  {%- endif -%}
                                  <input type="submit" class="button button--primary" value="{{ 'blogs.article.post' | t }}">
                              </div>
                          {%- endform -%}
                      </div>
                  </div>
              {%- endif -%}
            </div>
        </div>
    </div>
</article>

